// Setup Syntax
export const useUserStore = defineStore("user", () => {
  const user = ref(null);
  const fetchUser = async () => {
    const response = await fetch("/api/user");
    user.value = await response.json();
  }
  return {
    user,
    fetchUser,
  }
})

// Options Syntax
export const useUserStore = defineStore("user", {
  state: () => ({ user: null }),
  actions: {
    async fetchUser() {
      const response = await fetch("/api/user");
      this.user = await response.json();
    }
  }
})

